import React, { createContext, useContext, useEffect, useMemo, useState } from 'react';

const SettingsContext = createContext(null);

const LS_KEYS = { muteAudio: 'gp.muteAudio', psxDither: 'gp.psxDither' };

export function SettingsProvider({ children }) {
  const [muteAudio, setMuteAudio] = useState(() => {
    const saved = localStorage.getItem(LS_KEYS.muteAudio);
    return saved !== null ? saved === 'true' : false;
  });
  const [psxDither, setPsxDither] = useState(() => {
    const saved = localStorage.getItem(LS_KEYS.psxDither);
    return saved !== null ? saved === 'true' : false;
  });

  useEffect(() => {
    localStorage.setItem(LS_KEYS.muteAudio, String(muteAudio));
  }, [muteAudio]);

  useEffect(() => {
    localStorage.setItem(LS_KEYS.psxDither, String(psxDither));
  }, [psxDither]);

  const value = useMemo(() => ({ muteAudio, setMuteAudio, psxDither, setPsxDither }), [muteAudio, psxDither]);

  return (
    <SettingsContext.Provider value={value}>
      {children}
    </SettingsContext.Provider>
  );
}

export function useSettings() {
  const ctx = useContext(SettingsContext);
  if (!ctx) throw new Error('useSettings must be used within SettingsProvider');
  return ctx;
}
